// Este nodo asume que el array viene en item.json.precios.
// Ajusta la ruta si lo recibes en otro campo (por ejemplo, body o query).

const item = $input.first();          // Usamos el primer item del flujo
const precios = item.json.body.precios;    // <-- cambia aquí si tu campo se llama distinto

// Validaciones básicas
if (!Array.isArray(precios) || precios.length < 2) {
	throw new Error('Debes enviar un array "precios" con al menos 2 números.');
}
if (precios.some(p => typeof p !== 'number' || isNaN(p))) {
	throw new Error('Todos los valores de "precios" deben ser números.');
}

// 1) Ordenamos de mayor a menor
const ordenados = [...precios].sort((a, b) => b - a);

// 2) Calculamos descuento por posición (el primero no tiene)
const descuentos = ordenados.map((precio, idx) => {
	if (idx === 0) return 0;        // sin descuento para el más caro
	if (precio <= 50)  return 15;
	if (precio <= 100) return 20;
	return 25;                      // >100 €
});

// 3) Totales
const totalSinDescuento = ordenados.reduce((s, p) => s + p, 0);
const descuentoTotal    = descuentos.reduce((s, d) => s + d, 0);
const totalConDescuento = totalSinDescuento - descuentoTotal;

// 4) Preparar respuesta
const resumen =
	`Presupuesto total sin descuento (si vinieras a repararlo por separado): ${totalSinDescuento.toFixed(2)} €\n` +
	`Descuento aplicado (al ser varias reparaciones): ${descuentoTotal.toFixed(2)} €\n` +
	`Presupuesto reparándolo todo junto (y sólo viniendo una vez): ${totalConDescuento.toFixed(2)} €`;

return [
	{
		json: {
			resumen
		}
	}
];
